"use client";

import { useState } from "react";
import {
  User,
  Activity,
  FileText,
  Hospital,
  Upload,
} from "lucide-react";

export default function AddRecordForm() {
  const [form, setForm] = useState({
    patientId: "",
    disease: "",
    symptoms: "",
    prescription: "",
    hospitalName: "",
  });

  const [file, setFile] = useState<File | null>(null);
  const [loading, setLoading] = useState(false);

  const handleChange = (e: any) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const handleSubmit = async () => {
    try {
      setLoading(true);

      const formData = new FormData();

      formData.append("patientId", form.patientId);
      formData.append("disease", form.disease);
      formData.append(
        "symptoms",
        JSON.stringify(form.symptoms.split(","))
      );
      formData.append("prescription", form.prescription);
      formData.append("hospitalName", form.hospitalName);

      if (file) formData.append("report", file);

      const res = await fetch(
        "http://localhost:5000/api/records/add",
        {
          method: "POST",
          headers: {
            Authorization: `Bearer ${localStorage.getItem("token")}`,
          },
          body: formData,
        }
      );

      await res.json();
      alert("Record added successfully 🚀");
    } catch (error) {
      console.error(error);
      alert("Failed to add record");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="space-y-6">
      
      {/* Section: Patient Info */}
      <div>
        <h3 className="text-lg font-semibold text-white mb-3">
          Patient Information
        </h3>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          
          {/* Patient ID */}
          <div className="relative">
            <User className="absolute left-3 top-3 text-gray-400 w-5 h-5" />
            <input
              name="patientId"
              placeholder="Patient ID"
              onChange={handleChange}
              className="w-full pl-10 pr-3 py-2 rounded-lg bg-white/10 text-white placeholder-gray-400 border border-white/10 focus:outline-none focus:ring-2 focus:ring-indigo-500"
            />
          </div>

          {/* Hospital */}
          <div className="relative">
            <Hospital className="absolute left-3 top-3 text-gray-400 w-5 h-5" />
            <input
              name="hospitalName"
              placeholder="Hospital Name"
              onChange={handleChange}
              className="w-full pl-10 pr-3 py-2 rounded-lg bg-white/10 text-white placeholder-gray-400 border border-white/10 focus:outline-none focus:ring-2 focus:ring-indigo-500"
            />
          </div>
        </div>
      </div>

      {/* Section: Medical Details */}
      <div>
        <h3 className="text-lg font-semibold text-white mb-3">
          Medical Details
        </h3>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          
          {/* Disease */}
          <div className="relative">
            <Activity className="absolute left-3 top-3 text-gray-400 w-5 h-5" />
            <input
              name="disease"
              placeholder="Disease"
              onChange={handleChange}
              className="w-full pl-10 pr-3 py-2 rounded-lg bg-white/10 text-white placeholder-gray-400 border border-white/10 focus:outline-none focus:ring-2 focus:ring-indigo-500"
            />
          </div>

          {/* Symptoms */}
          <div className="relative">
            <FileText className="absolute left-3 top-3 text-gray-400 w-5 h-5" />
            <input
              name="symptoms"
              placeholder="Symptoms (comma separated)"
              onChange={handleChange}
              className="w-full pl-10 pr-3 py-2 rounded-lg bg-white/10 text-white placeholder-gray-400 border border-white/10 focus:outline-none focus:ring-2 focus:ring-indigo-500"
            />
          </div>
        </div>

        {/* Prescription (Full Width) */}
        <div className="relative mt-4">
          <FileText className="absolute left-3 top-3 text-gray-400 w-5 h-5" />
          <textarea
            name="prescription"
            placeholder="Prescription"
            onChange={handleChange}
            rows={3}
            className="w-full pl-10 pr-3 py-2 rounded-lg bg-white/10 text-white placeholder-gray-400 border border-white/10 focus:outline-none focus:ring-2 focus:ring-indigo-500"
          />
        </div>
      </div>

      {/* File Upload */}
      <div>
        <h3 className="text-lg font-semibold text-white mb-3">
          Upload Report
        </h3>

        <label className="flex items-center justify-center gap-2 border border-dashed border-white/20 rounded-xl p-4 cursor-pointer hover:bg-white/5 transition">
          <Upload className="w-5 h-5 text-gray-400" />
          <span className="text-gray-400 text-sm">
            {file ? file.name : "Click to upload report"}
          </span>

          <input
            type="file"
            hidden
            onChange={(e) => setFile(e.target.files?.[0] || null)}
          />
        </label>
      </div>

      {/* Submit */}
      <button
        onClick={handleSubmit}
        disabled={loading}
        className="w-full py-2.5 rounded-lg bg-gradient-to-r from-indigo-500 to-sky-500 text-white font-medium shadow-lg hover:scale-[1.02] hover:shadow-xl transition-all duration-300 flex items-center justify-center gap-2 disabled:opacity-70"
      >
        {loading ? "Submitting..." : "Submit Record"}
      </button>
    </div>
  );
}